def fermat(n,steps=2000000):
 a=isqrt(n)
 if a*a<n:a+=1
 for i in range(steps):
  b2=a*a-n
  b=isqrt(b2)
  if b*b==b2:
   return a-b,a+b,i
  a+=1
 return None
